/**
 * Asset Path Helper
 * ===================
 * Wraps Gatsby's `withPrefix` to resolve asset paths correctly
 * regardless of deployment target.
 *
 * Direct `<img src="/cigar-vitola/...">` paths break when deploying
 * to a subdirectory (e.g. GitHub Pages). Use this helper instead:
 *
 *   import { asset } from '../utils/assetPath';
 *   <img src={asset('/cigar-vitola/-pluss-count.png')} alt="" />
 *
 *   // Also works with relative paths:
 *   import { withPrefix } from '../utils/assetPath';
 *   <img src={withPrefix('/cigar-vitola/-pluss-count.png')} alt="" />
 */

let gatsbyWithPrefix

/**
 * Lazy-load Gatsby's `withPrefix` so this module can be imported
 * safely during SSR / build without crashing.
 */
function getWithPrefix() {
  if (!gatsbyWithPrefix) {
    try {
      // eslint-disable-next-line import/no-unresolved
      const { withPrefix } = require('gatsby')
      gatsbyWithPrefix = withPrefix
    } catch {
      // Fallback when Gatsby is not available (e.g. tests)
      gatsbyWithPrefix = (path) => path
    }
  }
  return gatsbyWithPrefix
}

/**
 * Resolve an asset path, automatically prepending the path prefix
 * (e.g. `/cigarBrevasWEBsite-AffinityeDEsign-From/cigar-vitola/...`).
 *
 * @param {string} path - Asset path (absolute, starting with /)
 * @returns {string} Correctly prefixed path
 *
 * @example
 *   asset('/footer/-logo-msn-whatup.webp')
 *   // → "/cigarBrevasWEBsite-AffinityeDEsign-From/footer/-logo-msn-whatup.webp"
 */
function asset(path) {
  const fn = getWithPrefix()

  // Gatsby's withPrefix only prepends if the path starts with /
  // and the site has a pathPrefix configured
  if (typeof path === 'string' && path.startsWith('/')) {
    return fn(path)
  }
  return path
}

/**
 * Re-export withPrefix for clarity.
 */
function withPrefix(path) {
  return asset(path)
}

module.exports = { asset, withPrefix }
